#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=4e4+10,M=1e6+10,NN=1.1e8+10;
bool ff1;
vector<int> G[N];int fa[N],buf[NN],*f[N],n,K,*g[N];bool isf[N];
int c[N],w[N],d1[N],d2[N],p1[N],p2[N],dep[N],siz[N],cd1,cd2;
bool ff2;
inline void Init()
{
	memset(isf,0,sizeof(isf));
	memset(buf,0,sizeof(buf));
	dep[1]=cd1=cd2=0;
}
inline void dfs1(int u)
{
	siz[u]=1;dep[u]+=w[u];
	for(int v:G[u])dep[v]=dep[u],dfs1(v),siz[u]+=siz[v];
	d1[p1[u]=++cd1]=u;
}
inline void dfs2(int u){for(int v:G[u])dfs2(v);d2[p2[u]=++cd2]=u;}
int q1[M],q2[M],H,T;
inline void DP(int *dfn,int **dp)
{
	rep(1,n,i)
	{
		
		int u=dfn[i];q1[H=T=0]=q2[0]=0;
		rep(1,K,j)
		{
//			if(i==19&&(j==282277||j==282276))printf("%d :: %d :: %d %d %d\n",i,j,H,T,i-siz[u]);
			while(H<=T&&q1[H]<j-c[u])++H;
//			if(i==19&&(j==282277||j==282276))printf("%d :: %d :: %d %d %d %d\n",i,j,n,K+1,max(q2[H]+j*w[u],dp[i-siz[u]][j]));
			dp[i][j]=max(q2[H]+j*w[u],dp[i-siz[u]][j]);
			int tmp=dp[i-1][j]-j*w[u];
			while(H<=T&&q2[T]<=tmp)--T;q1[++T]=j;q2[T]=tmp;
			
		}
//		printf("%d\n",i);
	}
}
inline void Solve()
{
	Init();int qn=n=read();K=read();
//	printf("Qry :: %d %d\n",qn,K);
	rep(1,qn,i)
	{
		G[i].clear();isf[fa[i]=read()]=true;if(fa[i])G[fa[i]].push_back(i);
		c[i]=read();w[i]=read();if(c[i]>1){c[++n]=c[i]-1;c[i]=1;w[n]=w[i];G[i].push_back(n);}
	}
	int *tmp=buf,cnt=0;rep(0,n,i)f[i]=tmp,tmp+=K+1,cnt+=K+1;rep(0,n,i)g[i]=tmp,tmp+=K+1,cnt+=K+1;
//	printf("QAQ :: %d\n",cnt);assert(0);
	dfs1(1);rep(1,n,i)reverse(G[i].begin(),G[i].end());dfs2(1);DP(d1,f);DP(d2,g);
	int ans=0;rep(1,qn,i)if(!isf[i])rep(0,K,j)ans=max(ans,f[p1[i]-1][j]+dep[i]+g[p2[i]-siz[i]][K-j]);
	printf("%d\n",ans);
}
int main()
{
//	printf("%.6lf\n",1.*(&ff1-&ff2)/1024/1024);
	int T=read();while(T--)Solve();return 0;
}
